const raw = $input.all()[0].json;
const content = raw.choices[0].message.content;
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = { safe: true }; }
return [{ json: {
  guardrail_safe: parsed.safe !== false,
  guardrail_reason: parsed.reason || null,
  route: parsed.safe !== false ? 'pass' : 'block'
}}];
